63	async function postJson<T>(url: string, body: unknown): Promise<T> {
64	  const res = await fetch(url, {
65	    method: 'POST',
66	    headers: { 'content-type': 'application/json' },
67	    body: JSON.stringify(body),
68	  });
69	  const text = await res.text();
70	  if (!res.ok) {
71	    throw new Error(`${res.status} ${res.statusText}: ${text}`);
72	  }
